1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	interface Item {
15	  type: string;
16	  cursed?: boolean;
17	  enchantment?: number;
18	  material?: string;
19	}
20	
21	interface Step {
22	  op: string;
23	  items?: Item[];
24	}
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BLOCK_SIZE = 3;
32	const BLOCK_PREMIUM = 60;
33	const CURSE_SURCHARGE_PERCENT = 50;
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
37	
38	const itemBasePremium = (item: Item): number => {
39	  const base = BASE_PREMIUM[item.type];
40	  const curse = item.cursed ? (base * CURSE_SURCHARGE_PERCENT) / PERCENT_BASE : 0;
41	  return base + curse;
42	};
43	
44	const sumBase = (items: Item[]): number =>
45	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
46	
47	const partitionByType = (items: Item[]): Item[][] => {
48	  const groups: Record<string, Item[]> = {};
49	  items.forEach((item) => (groups[item.type] ??= []).push(item));
50	  return Object.values(groups);
51	};
52	
53	const priceGroup = (group: Item[]): number =>
54	  group.length === BLOCK_SIZE && isComponent(group[0])
55	    ? BLOCK_PREMIUM
56	    : sumBase(group);
57	
58	const sumBasePremiums = (items: Item[]): number =>
59	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
60	
61	const applyFirstInsuranceSurcharge = (base: number): number =>
62	  Math.ceil((base * (PERCENT_BASE + FIRST_INSURANCE_PERCENT)) / PERCENT_BASE);
63	
64	const quotePremium = (items: Item[]): number =>
65	  applyFirstInsuranceSurcharge(sumBasePremiums(items)) + PROCESSING_FEE;
66	
67	const executeStep = (step: Step): { premium: number } => ({
68	  premium: quotePremium(step.items ?? []),
69	});
70	
71	export const runScenario = (input: unknown): { results: unknown[] } => {
72	  const scenario = input as Scenario;
73	  return { results: scenario.steps.map(executeStep) };
74	};
